export const dispatchConfig: DispatchConfig = {
  kindDefs: { direction: 'syn', compute: dispatch_kindDefs },
  defEnv: { direction: 'inh', computeRoot: dispatch_defEnv_root },
  defLookup: { direction: 'syn', compute: dispatch_defLookup },
  kindAnnotations: { direction: 'syn', compute: dispatch_kindAnnotations },
  contextFor: { direction: 'inh', computeRoot: dispatch_contextFor_root, computeParent: dispatch_contextFor_parent },
  violationFor: { direction: 'syn', compute: dispatch_violationFor },
  allViolations: { direction: 'syn', compute: dispatch_allViolations },
  nodeCount: { direction: 'collection', init: 1, combine: (acc: number, contrib: number) => acc + contrib },
};
